windowclass.script:
function onInit()
	self.onLockModeChanged(WindowManager.getWindowReadOnlyState(self));
end
function onLockModeChanged(bReadOnly)
	WindowManager.callSafeControlsSetLockMode(self, { "list_iadd", "ingredient_idelete_header", }, bReadOnly);
	if bReadOnly then
		self.updateIngredientSortFields();
	end
end
function updateIngredientSortFields()
	for _, w in pairs(list.getWindows()) do
		if w.updateSortFields then
			w.updateSortFields();
		end
	end
end
function cookSelectedIngredients()
	BetterToolsCookingManager.cookSelectedIngredients(self);
end

function onInit()
	self.onLockModeChanged(WindowManager.getWindowReadOnlyState(self));
end
function onLockModeChanged(bReadOnly)
	WindowManager.callSafeControlsSetLockMode(self, { "list_iadd", }, bReadOnly);
end

function onInit()
	BetterToolsAlchemyManager.ensureDefaultRows(getDatabaseNode());
	self.onLockModeChanged(WindowManager.getWindowReadOnlyState(self));
end
function onLockModeChanged(bReadOnly)
	creaturetype_button.setEnabled(true);
	harvest_button.setVisible(true);
	craftitem_button.setEnabled(true);
	craftlevel.setEnabled(true);
	craft_button.setVisible(true);
	for _, w in pairs(list.getWindows()) do
		if w.onLockModeChanged then
			w.onLockModeChanged(bReadOnly);
		end
	end
end
function harvest()
	BetterToolsAlchemyManager.performHarvest(getDatabaseNode());
end
function craft()
	BetterToolsAlchemyManager.craftSelectedItem(getDatabaseNode());
end
function chooseCreatureType()
	BetterToolsAlchemyManager.openCreatureTypePicker(getDatabaseNode());
end
function chooseItem()
	BetterToolsAlchemyManager.openItemPicker(getDatabaseNode());
end

local _bSyncing = false;

function onInit()
	self.sync();
	self.onLockModeChanged(WindowManager.getWindowReadOnlyState(self));
end
function sync()
	_bSyncing = true;
	BetterToolsAlchemyManager.updateMaterialDisplays(getDatabaseNode());
	_bSyncing = false;
end
function onLockModeChanged(bReadOnly)
	materialdisplay1.setReadOnly(bReadOnly);
	materialdisplay2.setReadOnly(bReadOnly);
	materialdisplay3.setReadOnly(bReadOnly);
end
function onDisplayChanged(nPotency, sValue)
	if _bSyncing then
		return;
	end
	BetterToolsAlchemyManager.setMaterialDisplayValue(getDatabaseNode(), nPotency, sValue);
end

function onInit()
	self.updateItemAvailability();
end
function choose(sItem)
	BetterToolsAlchemyManager.chooseItem(getDatabaseNode(), sItem);
	self.close();
end
function setItemEnabled(sControl, sItem)
	local cButton = self[sControl];
	if cButton then
		cButton.setEnabled(BetterToolsAlchemyManager.hasMaterialsForItem(getDatabaseNode(), sItem));
	end
end
function updateItemAvailability()
	self.setItemEnabled("pick_antiarkanum", "antiarkanum");
	self.setItemEnabled("pick_drachenbruehe", "drachenbruehe");
	self.setItemEnabled("pick_alchemistenfeuer", "alchemistenfeuer");
	self.setItemEnabled("pick_wutpulver", "wutpulver");
	self.setItemEnabled("pick_goetterfackel", "goetterfackel");
	self.setItemEnabled("pick_menschlichkeit", "menschlichkeit");
	self.setItemEnabled("pick_systemschock", "systemschock");
	self.setItemEnabled("pick_berserkerdunst", "berserkerdunst");
	self.setItemEnabled("pick_egelsamen", "egelsamen");
	self.setItemEnabled("pick_hehrgas", "hehrgas");
	self.setItemEnabled("pick_schlitterseife", "schlitterseife");
	self.setItemEnabled("pick_buschdaempfe", "buschdaempfe");
	self.setItemEnabled("pick_teufelssaeuseln", "teufelssaeuseln");
	self.setItemEnabled("pick_grabesluft", "grabesluft");
end

local _bUpdatingDowntimeFlasks = false;

function onInit()
	self.ensureDefaultFlasks();
	self.ensureGatherDefaults();
	self.onLockModeChanged(WindowManager.getWindowReadOnlyState(self));
end
function onLockModeChanged(bReadOnly)
	downtime_herb_button.setVisible(true);
	downtime_herb_button.setEnabled(true);
	harvest_hours.setEnabled(true);
	downtime_days.setEnabled(true);
end
function getFlaskCount()
	local nCount = 0;
	for _, _ in pairs(list.getWindows()) do
		nCount = nCount + 1;
	end
	return nCount;
end
function ensureDefaultFlasks()
	for i = self.getFlaskCount() + 1, 6 do
		list.createWindow();
	end
end
function ensureGatherDefaults()
	if harvest_hours.getValue() <= 0 then
		harvest_hours.setValue(1);
	end
	if downtime_days.getValue() <= 0 then
		downtime_days.setValue(1);
	end
	if downtime_flask.getValue() <= 0 then
		downtime_flask.setValue(BetterToolsHerbalismManager.getPreferredFlaskForHerb(getDatabaseNode(), downtime_herb.getValue()));
	end
	if downtime_herb.getValue() ~= "" then
		downtime_herblabel.setValue(BetterToolsHerbalismManager.getHerbLabel(downtime_herb.getValue()));
	end
	self.updateDowntimeFlaskChoices(true);
end
function harvest()
	self.ensureGatherDefaults();
	BetterToolsHerbalismManager.performHarvest(getDatabaseNode(), harvest_hours.getValue());
end
function downtime()
	self.ensureGatherDefaults();
	BetterToolsHerbalismManager.performDowntime(getDatabaseNode(), downtime_herb.getValue(), downtime_days.getValue(), downtime_flask.getValue());
end
function chooseDowntimeHerb()
	BetterToolsHerbalismManager.openHerbPicker(getDatabaseNode(), "downtime_herb");
end
function setDowntimeFlaskChoiceEnabled(nFlask, bEnabled)
	if nFlask == 1 then downtime_flask1.setEnabled(bEnabled);
	elseif nFlask == 2 then downtime_flask2.setEnabled(bEnabled);
	elseif nFlask == 3 then downtime_flask3.setEnabled(bEnabled);
	elseif nFlask == 4 then downtime_flask4.setEnabled(bEnabled);
	elseif nFlask == 5 then downtime_flask5.setEnabled(bEnabled);
	elseif nFlask == 6 then downtime_flask6.setEnabled(bEnabled);
	end
end
function setDowntimeFlaskChoiceValues(nSelected)
	_bUpdatingDowntimeFlasks = true;
	downtime_flask1.setValue(nSelected == 1 and 1 or 0);
	downtime_flask2.setValue(nSelected == 2 and 1 or 0);
	downtime_flask3.setValue(nSelected == 3 and 1 or 0);
	downtime_flask4.setValue(nSelected == 4 and 1 or 0);
	downtime_flask5.setValue(nSelected == 5 and 1 or 0);
	downtime_flask6.setValue(nSelected == 6 and 1 or 0);
	_bUpdatingDowntimeFlasks = false;
end
function isDowntimeFlaskCompatible(nFlask)
	return BetterToolsHerbalismManager.isFlaskCompatibleForHerb(getDatabaseNode(), downtime_herb.getValue(), nFlask);
end
function selectDowntimeFlask(nFlask)
	if _bUpdatingDowntimeFlasks then
		return;
	end
	if not self.isDowntimeFlaskCompatible(nFlask) then
		self.updateDowntimeFlaskChoices(true);
		return;
	end
	downtime_flask.setValue(nFlask);
	self.updateDowntimeFlaskChoices(true);
end
function updateDowntimeFlaskChoices(bKeepSelection)
	local sHerb = downtime_herb.getValue();
	local nSelected = downtime_flask.getValue();
	if sHerb == "" then
		downtime_flask.setValue(0);
		for i = 1, 6 do
			self.setDowntimeFlaskChoiceEnabled(i, false);
		end
		self.setDowntimeFlaskChoiceValues(0);
		return;
	end

	if not bKeepSelection or nSelected <= 0 or not self.isDowntimeFlaskCompatible(nSelected) then
		nSelected = BetterToolsHerbalismManager.getPreferredFlaskForHerb(getDatabaseNode(), sHerb);
		downtime_flask.setValue(nSelected);
	end
	for i = 1, 6 do
		self.setDowntimeFlaskChoiceEnabled(i, self.isDowntimeFlaskCompatible(i));
	end
	self.setDowntimeFlaskChoiceValues(nSelected);
end

function onInit()
	if completed.getValue() == 1 then
		self.close();
	end
end
function onCompletedChanged()
	if completed.getValue() == 1 then
		self.close();
	end
end

local _bUpdatingFlasks = false;

function onInit()
	BetterToolsHerbalismManager.syncHarvestEntryRemaining(getDatabaseNode());
	if flaskno.getValue() <= 0 then
		flaskno.setValue(BetterToolsHerbalismManager.getPreferredHarvestFlask(getDatabaseNode()));
	end
	self.updateHeaderState();
	self.updateFlaskChoices();
end
function allocate()
	if isheader.getValue() == 1 then
		BetterToolsHerbalismManager.allocateHarvestHour(getDatabaseNode());
	end
end
function setFlaskChoiceVisible(bVisible)
	flask1.setVisible(bVisible);
	flask2.setVisible(bVisible);
	flask3.setVisible(bVisible);
	flask4.setVisible(bVisible);
	flask5.setVisible(bVisible);
	flask6.setVisible(bVisible);
end
function setFlaskChoiceEnabled(nFlask, bEnabled)
	if nFlask == 1 then flask1.setEnabled(bEnabled);
	elseif nFlask == 2 then flask2.setEnabled(bEnabled);
	elseif nFlask == 3 then flask3.setEnabled(bEnabled);
	elseif nFlask == 4 then flask4.setEnabled(bEnabled);
	elseif nFlask == 5 then flask5.setEnabled(bEnabled);
	elseif nFlask == 6 then flask6.setEnabled(bEnabled);
	end
end
function setFlaskChoiceValues(nSelected)
	_bUpdatingFlasks = true;
	flask1.setValue(nSelected == 1 and 1 or 0);
	flask2.setValue(nSelected == 2 and 1 or 0);
	flask3.setValue(nSelected == 3 and 1 or 0);
	flask4.setValue(nSelected == 4 and 1 or 0);
	flask5.setValue(nSelected == 5 and 1 or 0);
	flask6.setValue(nSelected == 6 and 1 or 0);
	_bUpdatingFlasks = false;
end
function isFlaskCompatible(nFlask)
	return BetterToolsHerbalismManager.isHarvestFlaskCompatible(getDatabaseNode(), nFlask);
end
function getFirstCompatibleFlask()
	return BetterToolsHerbalismManager.getPreferredHarvestFlask(getDatabaseNode());
end
function selectFlask(nFlask)
	if _bUpdatingFlasks then
		return;
	end
	if isheader.getValue() == 1 then
		return;
	end
	if not self.isFlaskCompatible(nFlask) then
		self.updateFlaskChoices();
		return;
	end
	flaskno.setValue(nFlask);
	self.updateFlaskChoices();
end
function updateFlaskChoices()
	local bHeader = (isheader.getValue() == 1);
	local bSpacer = (isspacer.getValue() == 1);
	self.setFlaskChoiceVisible(not bHeader and not bSpacer);
	if bHeader or bSpacer then
		self.setFlaskChoiceValues(0);
		return;
	end

	local nSelected = flaskno.getValue();
	if nSelected <= 0 or not self.isFlaskCompatible(nSelected) then
		nSelected = self.getFirstCompatibleFlask();
		flaskno.setValue(nSelected);
	end

	for i = 1, 6 do
		self.setFlaskChoiceEnabled(i, self.isFlaskCompatible(i));
	end
	self.setFlaskChoiceValues(nSelected);
end
function updateHeaderState()
	local bHeader = (isheader.getValue() == 1);
	local bSpacer = (isspacer.getValue() == 1);
	groupheader.setValue(groupname.getValue());
	hour.setVisible(false);
	remaining.setVisible(false);
	herblabel.setVisible(not bHeader and not bSpacer);
	amount.setVisible(not bHeader and not bSpacer);
	allocate_button.setVisible(bHeader);
	groupheader.setVisible(bHeader and not bSpacer);
	self.updateFlaskChoices();
end

function onInit()
	BetterToolsLeisureManager.ensureDefaultRows(getDatabaseNode());
	self.onLockModeChanged(WindowManager.getWindowReadOnlyState(self));
end
function onLockModeChanged(bReadOnly)
	WindowManager.callSafeControlsSetLockMode(self, { "region_iadd" }, bReadOnly);
	for _, w in pairs(activities.getWindows()) do
		if w.onLockModeChanged then
			w.onLockModeChanged(bReadOnly);
		end
	end
	for _, w in pairs(list.getWindows()) do
		if w.onLockModeChanged then
			w.onLockModeChanged(bReadOnly);
		end
	end
end
function play()
	BetterToolsLeisureManager.performSelectedPlay(getDatabaseNode());
end
function downtime()
	BetterToolsLeisureManager.performDowntime(getDatabaseNode(), downtime_weeks.getValue());
end

function onInit()
	BetterToolsLeisureManager.updateActivity(getDatabaseNode());
	self.onLockModeChanged(WindowManager.getWindowReadOnlyState(self));
end
function onLockModeChanged(bReadOnly)
	idelete.setVisible(false);
	category_button.setVisible(not bReadOnly);
	category_button.setEnabled(not bReadOnly);
	categorylabel_locked_spacer.setVisible(bReadOnly);
	selected.setEnabled(true);
	usecharisma.setEnabled(not bReadOnly);
end
function chooseCategory()
	BetterToolsLeisureManager.openCategoryPicker(getDatabaseNode());
end
function select()
	BetterToolsLeisureManager.selectActivity(getDatabaseNode());
end

button_listitem_checkbox_left.script:
function onValueChanged()
	if getValue() == 1 then
		window.select();
	end
end

windowclass.script:
function choose(sCategory)
	local nodeActivity = DB.findNode(DB.getValue(getDatabaseNode(), "targetpath", ""));
	BetterToolsLeisureManager.chooseCategory(nodeActivity, sCategory);
	close();
end
function onClose()
	if DB.deleteNode then
		pcall(DB.deleteNode, getDatabaseNode());
	end
end

function onInit()
	BetterToolsLeisureManager.updateRegion(getDatabaseNode());
	self.onLockModeChanged(WindowManager.getWindowReadOnlyState(self));
end
function onLockModeChanged(bReadOnly)
	idelete.setVisible(not bReadOnly);
	idelete_spacer.setVisible(bReadOnly);
	name.setReadOnly(bReadOnly);
	fame.setReadOnly(bReadOnly);
end
function select()
	BetterToolsLeisureManager.selectRegion(getDatabaseNode());
end

button_listitem_checkbox_left.script:
function onValueChanged()
	if getValue() == 1 then
		window.select();
	end
end

windowclass.script:
function onInit()
	self.onLockModeChanged(WindowManager.getWindowReadOnlyState(self));
end
function onLockModeChanged(bReadOnly)
	WindowManager.callSafeControlsSetLockMode(self, { "list_iadd", "idelete_header", }, bReadOnly);
end

button_listitem_roll_right.script:
function onDragStart(button, x, y, draginfo)
	return window.action(draginfo);
end
